<script setup lang="ts">
/**
 * iOS Style Select Component
 * iOS 风格下拉选择器组件
 */
export interface SelectOption {
  value: string | number;
  label: string;
  disabled?: boolean;
}

withDefaults(
  defineProps<{
    options: SelectOption[];
    placeholder?: string;
    label?: string;
    disabled?: boolean;
  }>(),
  {
    placeholder: '请选择...',
    label: undefined,
    disabled: false,
  },
);

const model = defineModel<string | number>({ default: '' });
</script>

<template>
  <div class="ios-select-wrapper">
    <label v-if="label" class="ios-select-label">{{ label }}</label>
    <div class="ios-select-container">
      <select v-model="model" :disabled="disabled" class="ios-select">
        <option v-if="placeholder" value="" disabled>{{ placeholder }}</option>
        <option v-for="opt in options" :key="opt.value" :value="opt.value" :disabled="opt.disabled">
          {{ opt.label }}
        </option>
      </select>
      <i class="fa-solid fa-chevron-down ios-select-icon"></i>
    </div>
  </div>
</template>

